<script setup lang="ts">
import { onMounted,ref } from 'vue';import { useRouter } from 'vue-router';import { fetchDeal,createOrder } from '@/services/trade';import { formatMoney } from '@/lib/currency';import { useUserSession } from '@/composables/useUserSession';import type { DealDetail } from '@/types/trade'
const props=defineProps<{dealId:number}>(),router=useRouter(),{state,openAuthDialog}=useUserSession();const deal=ref<DealDetail|null>(null),quantity=ref(1),loading=ref(true),errorMessage=ref('')
onMounted(async()=>{try{deal.value=await fetchDeal(props.dealId)}catch(e){errorMessage.value=e instanceof Error?e.message:'团购加载失败'}finally{loading.value=false}})
async function buy(){if(!state.accessToken){openAuthDialog({mode:'password',redirectTo:`/deals/${props.dealId}`});return}try{const order=await createOrder(props.dealId,quantity.value);await router.push(`/user/orders/${order.id}`)}catch(e){errorMessage.value=e instanceof Error?e.message:'下单失败'}}
</script>
<template><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><p v-else-if="loading" class="feedback">团购加载中...</p><section v-else-if="deal" class="detail-hero"><img :src="deal.coverImage" :alt="deal.title" class="detail-hero__image"><div class="detail-hero__body"><p class="eyebrow">{{deal.shopName}} · 已售 {{deal.soldCount}}</p><h1>{{deal.title}}</h1><p class="detail-hero__summary">{{deal.rules}}</p><div class="detail-hero__stats"><div><span>团购价</span><strong>{{formatMoney(deal.price,deal.currency)}}</strong></div><div><span>原价</span><strong>{{formatMoney(deal.originalPrice,deal.currency)}}</strong></div><div><span>有效期</span><strong>{{deal.validEnd}}</strong></div></div><div class="dish-list"><div v-for="item in deal.items" :key="item.id" class="dish-card"><span>{{item.name}} × {{item.quantity}}</span><strong>{{formatMoney(item.price,deal.currency)}}</strong></div></div><div class="hero-actions"><input v-model.number="quantity" type="number" min="1" max="20"><button class="primary-button" @click="buy">立即购买</button></div></div></section></template>
